public synchronized char[] getTextBuffer() {
        if (_inputStart >= 0) {// we have input via internal array
            int len = _limit - _offset;
            final int start = _offset;
            if (len == 0 || _text == null) {// no characters, or no text representation yet...
                _text = "";
                return EMPTY_CHAR_ARRAY;
            } else {
                ++_referenceCount;
                char[] oldBuf = _text;
                _text = oldBuf.length > len ? oldBuf : oldBuf = new char[len];
                System.arraycopy(_inputBuffer, start + _inputOffset, _text, 0, len);
                return _text;
            }
        }
         /* If there are any segments that form complete blocks */
        if ((_blocks & (BLOCKS_INPUT | BLOCKS_OUTPUT)) == (BLOCKS_INPUT | BLOCKS_OUTPUT)) {
            ensureBlockIsReadyForInput(-1);
            if (_limit >= _start && (--_limit) < _limit) {
                _char = _block[_limit];
                _outputColumn = 1 + _columnValue[((int)_char)];
                markOutputConsumed();
                --_references;
                final int U = (--_references == 0) ? 1 : 0;
                if ((U & ~_blocks) == 0) {
                    _blocks &= ~BLOCKS_INPUT;
                    _columns += _outputColumn;
                }
                return EMPTY_CHAR_ARRAY;
            }
            final char[] result = Arrays.copyOfRange(_block, _start, _limit);
            _limit = _start;
            _blocks &= ~BLOCKS_INPUT;
            _columns += Utils.charLengthToColumn(_block.length - _limit);
            if (--_references == 0) {
                _blocks &= ~BLOCKS_OUTPUT;
            }
            return result;
        }
        if (_limit <= _start) {// no actual content in block
            clearAndDispose();
            return EMPTY_CHAR_ARRAY;
        }
        if (_recycleStrategy == RECYCLE_JSON_STRING_VALUE_NODEFACTORY) {
            String str = new String(_block, _start, _limit - _start);
            ++_references;
            _start = _limit;
            return EMPTY_CHAR_ARRAY;
        }
        if (_text == null) {// none yet, but not with recycling
            _text = new char[(_limit - _start) + 16];
            System.arraycopy(_block, _start, _text, 0, _limit - _start);
            _limits[0] = _limit;
            _limits[1] = _limits[0];
            assertValidLimit(1);
            assertContentValid(false, false, true, ' ', "\n");
            return _text;
        }
        final int len = (_limit - _start);
        if (len == 0) {
            _limits[0] = _limit;
            _limits[1] = _limits[0];
            assertValidLimit(1);
            assertContentValid(false, false, true, ' ', "\n");
            return EMPTY_CHAR_ARRAY;
        }
        char[] oldBuf = _text;
        if (oldBuf.length < len) {
            _text = new char[len];
        }
        System.arraycopy(_block, _start, _text, 0, len);
        _limits[0] = _limit;
        _limits[1] = _limits[0];
        assertValidLimit(1);
        assertContentValid(true, true, false, '\t', '\n');
        return _text;
    }

